#nullable enable // autogenerated

using System.Collections.Generic;

using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Models;
using MVZ2.Vanilla.Callbacks;
using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Models;
using MVZ2.Vanilla.Properties;

using MVZ2Logic.Models;

using PVZEngine.Buffs;
using PVZEngine.Callbacks;
using PVZEngine.Level;

namespace MVZ2.GameContent.Buffs.Enemies
{
    [BuffDefinition(VanillaBuffNames.Enemy.WarriorResistance)]
    public class WarriorResistance : BuffDefinition
    {
        public WarriorResistance(string nsp, string name) : base(nsp, name)
        {
            AddTrigger(VanillaLevelCallbacks.PRE_ENTITY_TAKE_DAMAGE, PreEntityTakeDamageCallback);
            AddModelInsertion(LogicModelHelper.ANCHOR_CENTER, VanillaModelKeys.WarriorResistanceShield, VanillaModelID.WarriorResistanceShield);
        }
        private void PreEntityTakeDamageCallback(VanillaLevelCallbacks.PreTakeDamageParams param, CallbackResult callbackResult)
        {
            var damageInfo = param.input;
            var entity = damageInfo.Entity;

            if (entity == null)
                return;

            // 如果实体不处于近战攻击状态,移除这个Buff  
            if (entity.State != STATE_MELEE_ATTACK)
            {
                entity.RemoveBuffs<WarriorResistance>();
                return;
            }

            // 获取实体身上所有WarriorResistance实例  
            buffBuffer.Clear();
            entity.GetBuffs<WarriorResistance>(buffBuffer);
            if (buffBuffer.Count == 0)
                return;

            var buff = entity.GetFirstBuff<ExplosionProtection>();
            if (buff == null)
                return;

            
            
            var level = buff.GetProperty<float>(PROP_Resistance_Level);
            damageInfo.Multiply(1f - level);
            
        }
        private List<Buff> buffBuffer = new List<Buff>();
        public const int STATE_MELEE_ATTACK = VanillaEnemyStates.MELEE_ATTACK;
        public static readonly VanillaBuffPropertyMeta<float> PROP_Resistance_Level =
            new VanillaBuffPropertyMeta<float>("Resistance_Level");
    }
}
